import { createGame } from '../src/index.js';
import { BALANCE, getQuota } from '../src/data/balance.js';
import { PixelWheel } from './objects/PixelWheel.js';
import { PAL, PAL32, THEMES, THEME_ORDER, getCurrentTheme, getThemeLabel, setTheme, cycleTheme, onThemeChange } from './gfx/PaletteDB.js';
import { drawText, drawTextCentered, drawTextCenteredOutlined, drawTextWrapped, measureText, CHAR_W, CHAR_H } from './gfx/BitmapFont.js';
import { preloadSprites, drawSpriteCentered, drawAnimSpriteCentered, drawAnimFrameCentered, getAnimFrameCount, getSpriteIds, getAnimSpriteIds, SPRITE_SIZE } from './gfx/PixelSprites.js';
import { SYMBOLS, getSymbol } from '../src/data/symbols.js';
import { WHEEL_UPGRADES } from '../src/data/wheelUpgrades.js';
import { RELICS, RELIC_MAP } from '../src/data/relics.js';
import { CHOICES } from '../src/data/choices.js';
import { PostFXGL } from './gfx/PostFXGL.js';
import { playIntro, getIntroAudioCtx } from './intro.js';
import { getChiptuneEngine } from './audio/ChiptuneEngine.js';
import { MusicManager } from './audio/songs.js';

// ── Canvas resolution (CSS scales this to viewport with nearest-neighbor) ──
const W = 480, H = 270;
const PX = 2;                          // pixel scale — each art pixel = PX×PX canvas pixels
const CW = W * PX, CH = H * PX;       // canvas resolution (960×540)
const WHEEL_CX = 240, WHEEL_CY = 140;
const BG_PAD = 4;                      // background oversize for parallax shift

// ── Hieroglyph Ring constants ──
const HIERO_INNER = 174;           // inner radius of hieroglyph ring (13px gap outside ORBIT_OUTER=115)
const HIERO_OUTER = 220;           // outer radius (44px height — enlarged segments)
const HIERO_MID   = (HIERO_INNER + HIERO_OUTER) / 2;


// Menu glyphs (gear, exit, book) are now loaded as sprites from assets/menu/

// Menu segment definitions (indices relative to wheel segment count)
// Placed ~85% around the ring = upper-left quadrant
const HIERO_MENU_DEFS = [
  { offsetFromEnd: 12, id: 'catalogue', glyph: 'book' },
  { offsetFromEnd: 3,  id: 'retry',     glyph: 'arrow_right', scale: 3 },
  { offsetFromEnd: 4,  id: 'settings',  glyph: 'gear' },
  { offsetFromEnd: 5,  id: 'exit',      glyph: 'exit' },
];

const _BASE = import.meta.env.BASE_URL ?? '/';
const _CURSOR_DEFAULT = `url('${_BASE}assets/cursors/cursor_default.png') 0 0, auto`;
const _CURSOR_POINTER = `url('${_BASE}assets/cursors/cursor_pointer.png') 6 0, pointer`;

class App {
  constructor() {
    this._canvas = document.createElement('canvas');
    this._canvas.width = CW;
    this._canvas.height = CH;
    this._ctx = this._canvas.getContext('2d');

    // Display canvas (WebGL post-FX)
    this._display = document.getElementById('game');
    this._display.width = CW;
    this._display.height = CH;
    this._display.style.cursor = _CURSOR_DEFAULT;

    this.game = createGame({ seed: Date.now() });
    this.wheel = new PixelWheel();
    this._spinning = false;
    this._postSpinShow = true;
    this.wheel.setBonusMode(false);

    this._updateGaugeUnlocks();

    this._time = 0;
    this._pops = [];
    this._shake = { x: 0, y: 0, intensity: 0, decay: 0, time: 0 };
    this._flash = 0;
    this._goldDisplay = 0;
    this._postSpinShow = false;
    this._lastTicketDisplay = 0;
    this._lastTicketDisplay = this.game.getState().meta.tickets; // animated gold counter // invert flash timer (>0 = active)
    this._inShop = false;
    if (this._music) {
      const round = this.game.getState().run?.round || 1;
  
    }
    this._shopResolve = null;
    this._debugSpritesOpen = false;
    this._debugScroll = 0;
    this._relicHoverRarity = null; // hovered relic rarity for tooltip
    this._gameOverData = null; // { round, score, quota } when game over

    // Build default wheel data BEFORE background (background needs segment info)
    const defaultWheel = Array.from({ length: BALANCE.INITIAL_SEGMENTS }, (_, i) => ({
      id: 'seg_' + i, symbolId: null, weight: 1, modifiers: [],
    }));
    this.wheel.setWheel(defaultWheel);

    this._initBackground(defaultWheel);
    this._wheelDataForBg = defaultWheel;

    // ── Theme picker state ──
    this._themePickerOpen = false;
    this._themePickerHover = -1;

    // Rebuild palette-dependent pre-rendered canvases on theme change
    onThemeChange(() => {
      this._initBackground(this._wheelDataForBg);
      if (this.wheel) {
        this.wheel._forgeBgCanvas = null; // forge-shop bg uses lazy init
      }
    });

    // Mouse tracking (normalized -1..1 from center)
    this._mx = 0;
    this._my = 0;
    this._hubHover = false;
    this._sweepTrigger = -99;  // time of last hover-triggered sweep

    // Listen for game over
    this.game.on('game:over', (data) => {
      this._gameOverData = { round: data.round, score: data.totalWon, quota: data.quota };
    });

    // Start game immediately
    this.game.startRun();
    this._syncWheel();

    // GPU post-process (replaces CPU quantizer + CRT filter)
    this._postfx = new PostFXGL(this._display);

    // Lights overlay (screen blend via CSS — NOT quantized)
    this._lightsCanvas = document.createElement('canvas');
    this._lightsCanvas.width = CW;
    this._lightsCanvas.height = CH;
    this._lightsCanvas.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;pointer-events:none;mix-blend-mode:screen;image-rendering:pixelated;image-rendering:crisp-edges;';
    document.body.appendChild(this._lightsCanvas);
    this._lightsCtx = this._lightsCanvas.getContext('2d');

    // UI overlay (popups/menus — drawn AFTER postfx, NOT affected by shader)
    this._uiCanvas = document.createElement('canvas');
    this._uiCanvas.width = CW;
    this._uiCanvas.height = CH;
    this._uiCanvas.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;pointer-events:none;image-rendering:pixelated;image-rendering:crisp-edges;';
    document.body.appendChild(this._uiCanvas);
    this._uiCtx = this._uiCanvas.getContext('2d');

    // Audio
    this._audioCtx = null;
    this.wheel.onPegHit = () => this._tick();
    this.wheel.onBallEject = () => this._playEject();
    this.wheel.onFlipMid = () => this._shakeStart(3, 0.2);
    this.wheel.onFlipDone = () => this._shakeStart(8, 0.3);

    // Input (on display canvas)
    this._display.addEventListener('click', e => this._handleClick(e));
    this._display.addEventListener('mousemove', e => this._handleMouse(e));
    window.addEventListener('keydown', e => {
      if (e.key === 'Escape' && this._debugSpritesOpen) { this._debugSpritesOpen = false; e.preventDefault(); }
      else if (e.key === 'Escape' && this._catalogueOpen) { this._closeCatalogue(); e.preventDefault(); }
      else if (e.key === 'Escape' && this._themePickerOpen) { this._closeThemePicker(); e.preventDefault(); }
    });
    this._display.addEventListener('wheel', e => {
      if (this._debugSpritesOpen) {
        const ids = getSpriteIds().length + getAnimSpriteIds().length;
        const COLS = Math.floor((400 - 8) / 28);
        const ROWS = Math.floor((230 - 20) / 28);
        const maxScroll = Math.max(0, Math.ceil(ids / COLS) - ROWS);
        this._debugScroll = Math.max(0, Math.min(maxScroll, this._debugScroll + (e.deltaY > 0 ? 1 : -1)));
        e.preventDefault();
        return;
      }
      if (!this._catalogueOpen) return;
      const TAB_DATA_LENS = [WHEEL_UPGRADES.length, RELICS.length, CHOICES.length];
      const maxScroll = Math.max(0, TAB_DATA_LENS[this._catalogueTab] - 18);
      this._catalogueScroll = Math.max(0, Math.min(maxScroll, this._catalogueScroll + (e.deltaY > 0 ? 1 : -1)));
      e.preventDefault();
    }, { passive: false });

    // Render loop
    this._lastTime = 0;
    requestAnimationFrame(t => this._loop(t));
  }

  // ── Input ──
  _mapCoords(e) {
    const rect = this._display.getBoundingClientRect();
    return {
      x: Math.floor((e.clientX - rect.left) / rect.width * W),
      y: Math.floor((e.clientY - rect.top) / rect.height * H),
    };
  }

  _handleMouse(e) {
    const rect = this._display.getBoundingClientRect();
    this._mx = ((e.clientX - rect.left) / rect.width - 0.5) * 2;   // -1..1
    this._my = ((e.clientY - rect.top) / rect.height - 0.5) * 2;   // -1..1

    const x = Math.floor((e.clientX - rect.left) / rect.width * W);
    const y = Math.floor((e.clientY - rect.top) / rect.height * H);

    if (this._themePickerOpen) {
      const hit = this._themePickerHitTest(x, y);
      this._themePickerHover = hit;
      this._display.style.cursor = (hit >= 0) ? _CURSOR_POINTER : _CURSOR_DEFAULT;
      return;
    }
    // Relic bar hover detection (top gauge area) — blocked by overlays
    const oldRelicHover = this._relicHoverRarity;
    const relicHit = (this._catalogueOpen || this._debugSpritesOpen) ? null : this.wheel.relicBarHitTest(x, y, WHEEL_CX, WHEEL_CY);
    this._relicHoverRarity = relicHit;
    if (relicHit && relicHit !== oldRelicHover) this._playHover();

    if (this._inShop && this.wheel.flipped) {
      const oldShopHover = this.wheel._shop.hoverIdx;
      const hit = this.wheel.shopHitTest(x, y, WHEEL_CX, WHEEL_CY);
      this.wheel.shopSetHover(hit);
      if (this.wheel._shop.hoverIdx !== -1 && this.wheel._shop.hoverIdx !== oldShopHover) this._playHover();
      this._display.style.cursor = (hit || relicHit) ? _CURSOR_POINTER : _CURSOR_DEFAULT;
      return;
    }

    // Menu button hover detection (hieroglyph ring)
    const oldMenuHover = this._menuHover;
    const menuHit = this._hieroHitTest(x, y);
    this._menuHover = menuHit;
    if (menuHit && menuHit !== oldMenuHover) this._playHover();

    // Hub hover detection
    const dx = x - WHEEL_CX;
    const dy = (y - WHEEL_CY) / (this.wheel.tilt || 0.65);
    const wasHover = this._hubHover;
    this._hubHover = dx * dx + dy * dy < 40 * 40;
    this._display.style.cursor = (relicHit || menuHit || (this._hubHover && !this._spinning)) ? _CURSOR_POINTER : _CURSOR_DEFAULT;

    // Trigger sweep on hover enter
    if (this._hubHover && !wasHover) { this._sweepTrigger = this._time; this._playHover(); }
  }

  _handleClick(e) {
    this._initAudio();
    const { x, y } = this._mapCoords(e);

    // Theme picker overlay intercepts all clicks when open
    if (this._themePickerOpen) {
      this._themePickerClick(x, y);
      return;
    }
    // Debug sprites overlay intercepts all clicks when open
    if (this._debugSpritesOpen) {
      this._debugSpritesClick(x, y);
      return;
    }

    // Catalogue overlay intercepts all clicks when open
    if (this._catalogueOpen) {
      this._catalogueClick(x, y);
      return;
    }

    // ── Shop click handling ──
    if (this._inShop && this.wheel.flipped) {
      const hit = this.wheel.shopHitTest(x, y, WHEEL_CX, WHEEL_CY);
      if (hit) {
        this._handleShopClick(hit);
        return;
      }
    }

    // Menu button click (hieroglyph ring)
    const menuHit = this._hieroHitTest(x, y);
    if (menuHit) {
      this._onMenuClick(menuHit);
      return;
    }

    // Hub button click (ellipse hit test with tilt)
    const dx = x - WHEEL_CX;
    const dy = (y - WHEEL_CY) / (this.wheel.tilt || 0.65);
    if (dx * dx + dy * dy < 40 * 40) {
      if (this._spinning) return;

      const phase = this.game.getPhase();

      if (phase === 'FREE_SPIN_OFFER') {
        this._playSelect();
        this.game.acceptFreeSpin();
        this._syncWheel();
        this._doSpin();
        return;
      }

      if (this._gameOverData) {
        this._retryFromGameOver();
        return;
      }
      this._onAction();
      return;
    }
  }

  _onMenuClick(menuId) {
    this._playSelect();
    if (menuId === 'catalogue') {
      this._openCatalogue();
    } else if (menuId === 'settings') {
      this._openThemePicker();
    } else if (menuId === 'retry') {
      this._retryFromGameOver();
    } else if (menuId === 'exit') {
      this._pop('EXIT');
    }
  }

  _retryFromGameOver() {
    this._gameOverData = null;
    this._playSelect();
    this._shakeStart(4, 0.3);
    this.game.startRun();
    this._syncWheel();

  }

  // ── Theme picker overlay ──
  _openThemePicker() {
    this._playSelect();
    this._themePickerOpen = true;
    this._themePickerHover = -1;
  }

  _closeThemePicker() {
    this._themePickerOpen = false;
    this._themePickerHover = -1;
  }

  _getThemePickerRect() {
    const pw = 240, ph = 200;
    const px = Math.floor((W - pw) / 2);
    const py = Math.floor((H - ph) / 2);
    return { px, py, pw, ph };
  }

  _getThemeRowRect(i, panel) {
    const rowH = 22;
    const rx = panel.px + 8;
    const ry = panel.py + 24 + i * rowH;
    const rw = panel.pw - 16;
    return { rx, ry, rw, rh: rowH - 2 };
  }

  _themePickerHitTest(x, y) {
    const panel = this._getThemePickerRect();
    if (x < panel.px || x > panel.px + panel.pw || y < panel.py || y > panel.py + panel.ph) return -2; // outside = close
    for (let i = 0; i < THEME_ORDER.length; i++) {
      const r = this._getThemeRowRect(i, panel);
      if (x >= r.rx && x <= r.rx + r.rw && y >= r.ry && y <= r.ry + r.rh) return i;
    }
    return -1;
  }

  _themePickerClick(x, y) {
    const hit = this._themePickerHitTest(x, y);
    if (hit === -2) { this._playSelect(); this._closeThemePicker(); return; }
    if (hit >= 0) {
      const themeId = THEME_ORDER[hit];
      this._playSelect();
      setTheme(themeId);
    }
  }

  _drawThemePicker(ctx) {
    if (!this._themePickerOpen) return;
    // Dim backdrop
    ctx.fillStyle = 'rgba(0,0,0,0.55)';
    ctx.fillRect(0, 0, W, H);

    const panel = this._getThemePickerRect();
    ctx.fillStyle = PAL.black;
    ctx.fillRect(panel.px, panel.py, panel.pw, panel.ph);
    ctx.strokeStyle = PAL.gold; ctx.lineWidth = 1;
    ctx.strokeRect(panel.px + 0.5, panel.py + 0.5, panel.pw - 1, panel.ph - 1);

    drawTextCentered(ctx, 'COLOR THEME', panel.px + panel.pw / 2, panel.py + 6, PAL.gold, 1);

    const current = getCurrentTheme();
    const swatchKeys = ['red', 'gold', 'green', 'blue', 'purple', 'cyan', 'neonPink'];

    for (let i = 0; i < THEME_ORDER.length; i++) {
      const id = THEME_ORDER[i];
      const theme = THEMES[id];
      const r = this._getThemeRowRect(i, panel);
      const isCurrent = id === current;
      const isHover = i === this._themePickerHover;

      // Row bg
      if (isCurrent) {
        ctx.fillStyle = PAL.darkGold;
        ctx.fillRect(r.rx, r.ry, r.rw, r.rh);
      } else if (isHover) {
        ctx.fillStyle = PAL.darkGray;
        ctx.fillRect(r.rx, r.ry, r.rw, r.rh);
      }
      ctx.strokeStyle = isCurrent ? PAL.gold : (isHover ? PAL.midGray : PAL.darkGray);
      ctx.strokeRect(r.rx + 0.5, r.ry + 0.5, r.rw - 1, r.rh - 1);

      // Label
      const labelCol = isCurrent ? PAL.white : (isHover ? PAL.white : PAL.lightGray);
      drawText(ctx, theme.label.toUpperCase(), r.rx + 5, r.ry + 4, labelCol, 1);

      // Color swatch strip (right side)
      const swW = 9, swH = 10;
      const swY = r.ry + 5;
      let swX = r.rx + r.rw - swatchKeys.length * swW - 4;
      for (const key of swatchKeys) {
        ctx.fillStyle = theme.colors[key];
        ctx.fillRect(swX, swY, swW - 1, swH);
        swX += swW;
      }
    }

    drawTextCentered(ctx, '[ESC] CLOSE', panel.px + panel.pw / 2, panel.py + panel.ph - 10, PAL.darkGold, 1);
  }

  // ── Catalogue overlay ──
  _openCatalogue() {
    this._catalogueOpen = true;
    this._catalogueTab = 0;        // 0=symbols, 1=relics, 2=upgrades
    this._catalogueScroll = 0;
  }

  _closeCatalogue() {
    this._catalogueOpen = false;
  }

  _drawCatalogue(ctx) {
    if (!this._catalogueOpen) return;
    const TAB_NAMES = ['UPGRADES', 'RELIQUES', 'BILLES SP.'];
    const TAB_DATA = [
      WHEEL_UPGRADES.map(u => ({ name: u.name, sprite: null, rarity: u.rarity, desc: u.description })),
      RELICS.map(r => ({ name: r.name, sprite: 'relic_' + r.rarity, rarity: r.rarity, desc: r.description })),
      CHOICES.filter(c => c.type === 'special_ball').map(c => ({ name: c.name, sprite: 'ball', rarity: c.rarity, desc: c.description })),
    ];

    // Dims
    const PW = 320, PH = 200;
    const PX0 = Math.floor((W - PW) / 2), PY0 = Math.floor((H - PH) / 2);
    const TAB_H = 14, HEAD_H = 12, ROW_H = 10;
    const BODY_Y = PY0 + TAB_H + HEAD_H;
    const BODY_H = PH - TAB_H - HEAD_H - 6;
    const MAX_ROWS = Math.floor(BODY_H / ROW_H);

    // Backdrop
    ctx.fillStyle = 'rgba(0,0,0,0.82)';
    ctx.fillRect(PX0 - 2, PY0 - 2, PW + 4, PH + 4);
    ctx.fillStyle = PAL.black;
    ctx.fillRect(PX0, PY0, PW, PH);

    // Border
    ctx.strokeStyle = PAL.darkGold;
    ctx.lineWidth = 1;
    ctx.strokeRect(PX0 + 0.5, PY0 + 0.5, PW - 1, PH - 1);

    // Tabs
    const tabW = Math.floor(PW / TAB_NAMES.length);
    for (let t = 0; t < TAB_NAMES.length; t++) {
      const tx = PX0 + t * tabW;
      if (t === this._catalogueTab) {
        ctx.fillStyle = PAL.darkRed;
        ctx.fillRect(tx, PY0, tabW, TAB_H);
      }
      ctx.strokeStyle = PAL.darkGold;
      ctx.strokeRect(tx + 0.5, PY0 + 0.5, tabW - 1, TAB_H - 1);
      drawTextCentered(ctx, TAB_NAMES[t], tx + Math.floor(tabW / 2), PY0 + 3, t === this._catalogueTab ? PAL.gold : PAL.midGray, 1, t === this._catalogueTab);
    }

    // Column header
    const hdrY = PY0 + TAB_H + 1;
    drawText(ctx, 'NOM', PX0 + 4, hdrY, PAL.gold);
    drawText(ctx, 'DESCRIPTION', PX0 + 100, hdrY, PAL.gold);

    // Rows
    const items = TAB_DATA[this._catalogueTab];
    const scroll = this._catalogueScroll;
    const visible = items.slice(scroll, scroll + MAX_ROWS);
    const RARITY_COL = { common: PAL.white, uncommon: PAL.green, rare: PAL.blue, legendary: PAL.gold };
    for (let i = 0; i < visible.length; i++) {
      const it = visible[i];
      const ry = BODY_Y + i * ROW_H;
      const col = it.rarity ? (RARITY_COL[it.rarity] || PAL.white) : PAL.white;
      drawSpriteCentered(ctx, it.sprite, PX0 + 4 + Math.floor(SPRITE_SIZE / 2), ry + Math.floor(ROW_H / 2), 1);
      drawText(ctx, it.name, PX0 + 4 + SPRITE_SIZE + 2, ry, col);
      drawText(ctx, it.desc, PX0 + 100, ry, PAL.midGray, 1, false);
    }

    // Scrollbar hint
    if (items.length > MAX_ROWS) {
      const pct = scroll / Math.max(1, items.length - MAX_ROWS);
      const sbH = Math.max(8, Math.floor(BODY_H * MAX_ROWS / items.length));
      const sbY = BODY_Y + Math.floor((BODY_H - sbH) * pct);
      ctx.fillStyle = PAL.darkGold;
      ctx.fillRect(PX0 + PW - 5, sbY, 3, sbH);
    }

    // Close hint
    drawTextCentered(ctx, '[ESC] FERMER', PX0 + Math.floor(PW / 2), PY0 + PH - 9, PAL.darkGold);

    // Debug button below catalogue
    const dbtnW = 80, dbtnH = 12;
    const dbtnX = PX0 + Math.floor((PW - dbtnW) / 2);
    const dbtnY = PY0 + PH + 4;
    ctx.fillStyle = PAL.darkGray;
    ctx.fillRect(dbtnX, dbtnY, dbtnW, dbtnH);
    ctx.strokeStyle = PAL.midGray;
    ctx.lineWidth = 1;
    ctx.strokeRect(dbtnX + 0.5, dbtnY + 0.5, dbtnW - 1, dbtnH - 1);
    drawTextCentered(ctx, 'DEBUG SPRITES', dbtnX + Math.floor(dbtnW / 2), dbtnY + 2, PAL.white);
  }

  _catalogueClick(x, y) {
    // Debug button hit test
    const PW2 = 320, PH2 = 200;
    const PX02 = Math.floor((W - PW2) / 2), PY02 = Math.floor((H - PH2) / 2);
    const dbtnW = 80, dbtnH = 12;
    const dbtnX = PX02 + Math.floor((PW2 - dbtnW) / 2);
    const dbtnY = PY02 + PH2 + 4;
    if (x >= dbtnX && x <= dbtnX + dbtnW && y >= dbtnY && y <= dbtnY + dbtnH) {
      this._closeCatalogue();
      this._debugSpritesOpen = true;
      this._debugScroll = 0;
      return;
    }

    const PW = 320, PH = 200;
    const PX0 = Math.floor((W - PW) / 2), PY0 = Math.floor((H - PH) / 2);
    const TAB_H = 14;

    // Outside panel → close
    if (x < PX0 || x > PX0 + PW || y < PY0 || y > PY0 + PH) {
      this._closeCatalogue();
      return;
    }

    // Tab row click
    if (y >= PY0 && y < PY0 + TAB_H) {
      const tabW = Math.floor(PW / 3);
      const t = Math.floor((x - PX0) / tabW);
      if (t >= 0 && t < 3) {
        this._catalogueTab = t;
        this._catalogueScroll = 0;
      }
    }
  }

  // ── Debug sprites grid ──
  _drawDebugSprites(ctx) {
    if (!this._debugSpritesOpen) return;

    const ids = getSpriteIds();
    const animIds = getAnimSpriteIds();
    const allIds = [...ids, ...animIds.map(id => '~' + id)];

    const PW = 400, PH = 230;
    const PX0 = Math.floor((W - PW) / 2), PY0 = Math.floor((H - PH) / 2);
    const CELL = 28;       // cell size (sprite + label)
    const COLS = Math.floor((PW - 8) / CELL);
    const ROWS = Math.floor((PH - 20) / CELL);
    const maxScroll = Math.max(0, Math.ceil(allIds.length / COLS) - ROWS);
    this._debugScroll = Math.min(this._debugScroll, maxScroll);

    // Backdrop
    ctx.fillStyle = 'rgba(0,0,0,0.88)';
    ctx.fillRect(PX0 - 2, PY0 - 2, PW + 4, PH + 4);
    ctx.fillStyle = PAL.black;
    ctx.fillRect(PX0, PY0, PW, PH);
    ctx.strokeStyle = PAL.midGray;
    ctx.lineWidth = 1;
    ctx.strokeRect(PX0 + 0.5, PY0 + 0.5, PW - 1, PH - 1);

    // Title
    drawTextCentered(ctx, 'DEBUG SPRITES (' + allIds.length + ')', PX0 + Math.floor(PW / 2), PY0 + 3, PAL.white);

    // Grid
    const gridY0 = PY0 + 14;
    ctx.save();
    ctx.beginPath();
    ctx.rect(PX0, gridY0, PW, PH - 20);
    ctx.clip();

    for (let i = 0; i < allIds.length; i++) {
      const row = Math.floor(i / COLS) - this._debugScroll;
      const col = i % COLS;
      if (row < -1 || row > ROWS) continue;

      const cx = PX0 + 6 + col * CELL + Math.floor(CELL / 2);
      const cy = gridY0 + row * CELL + Math.floor(CELL / 2);

      const rawId = allIds[i];
      const isAnim = rawId.startsWith('~');
      const id = isAnim ? rawId.slice(1) : rawId;

      // Cell border
      ctx.strokeStyle = PAL.darkGray;
      ctx.strokeRect(cx - Math.floor(CELL / 2) + 0.5, cy - Math.floor(CELL / 2) + 0.5, CELL - 1, CELL - 1);

      // Sprite
      if (isAnim) {
        drawAnimSpriteCentered(ctx, id, cx, cy - 3, 1, this._time);
      } else {
        drawSpriteCentered(ctx, id, cx, cy - 3, 1);
      }

      // Label (truncated)
      const label = id.length > 5 ? id.slice(0, 4) + '.' : id;
      drawTextCentered(ctx, label, cx, cy + 7, isAnim ? PAL.gold : PAL.darkGold, 1, false);
    }

    ctx.restore();

    // Scrollbar
    if (maxScroll > 0) {
      const sbTotalH = PH - 20;
      const pct = this._debugScroll / maxScroll;
      const sbH = Math.max(8, Math.floor(sbTotalH * ROWS / Math.ceil(allIds.length / COLS)));
      const sbY = gridY0 + Math.floor((sbTotalH - sbH) * pct);
      ctx.fillStyle = PAL.midGray;
      ctx.fillRect(PX0 + PW - 5, sbY, 3, sbH);
    }

    // Close hint
    drawTextCentered(ctx, '[ESC] FERMER', PX0 + Math.floor(PW / 2), PY0 + PH - 9, PAL.midGray);
  }

  _debugSpritesClick(x, y) {
    // Any click closes the debug view
    this._debugSpritesOpen = false;
  }

  _handleShopClick(hit) {
    const state = this.game.getState();
    const run = state.run;
    const meta = state.meta;
    if (!run) return;

    if (hit.type === 'offering') {
      const offering = run.shopOfferings[hit.index];
      if (!offering) return;
      if (meta.tickets < offering.finalCost) {
        this._pop('NO TICKETS!');
        return;
      }
      this.wheel.shopRemoveOffering(hit.index);
      const ok = this.game.shopBuy(hit.index);
      if (ok) {
        const label = offering.shopType === 'symbol' ? 'ADDED!'
                    : offering.shopType === 'special_ball' ? 'ADDED!'
                    : 'BOUGHT!';
        // Compute popup position based on item type
        const popOpts = { noCoin: true, color: PAL.white };
        let popX, popY;
        if (offering.shopType === 'symbol' || offering.shopType === 'special_ball') {
          // Ball gauge: right side (angle 0), MID_R ~ 101 from wheel center
          popX = WHEEL_CX + 101;
          popY = WHEEL_CY;
        } else if (offering.shopType === 'relic') {
          // Relic bar: top (angle -π/2), MID_R ~ 101 from wheel center
          popX = WHEEL_CX;
          popY = WHEEL_CY - 101;
        } else {
          popX = WHEEL_CX;
          popY = WHEEL_CY - 50;
        }
        this._pop(label, popX, popY, popOpts);
        this._shakeStart(3, 0.2);
        this._playBuy();
        // Refresh shop display
        const rerollCost = BALANCE.SHOP_REROLL_BASE * Math.pow(2, run.rerollCount || 0);
        const nextQuota = getQuota(run.round + 1);
        this.wheel.setShop(run.shopOfferings, meta.tickets, rerollCost, nextQuota);
        // Update orbit slots with relics
        this._syncRelicSlots();
        // Re-sync wheel in case a symbol was added
        this._syncWheel();
      }
    } else if (hit.type === 'reroll') {
      const rerollCost = BALANCE.SHOP_REROLL_BASE * Math.pow(2, run.rerollCount || 0);
      if (meta.tickets < rerollCost) {
        this._pop('NO TICKETS!');
        return;
      }
      const ok = this.game.shopReroll();
      if (ok) {
        this._pop('REROLL!');
        this._shakeStart(2, 0.15);
        const newRerollCost = BALANCE.SHOP_REROLL_BASE * Math.pow(2, run.rerollCount || 0);
        const nextQuota = getQuota(run.round + 1);
        this.wheel.setShop(run.shopOfferings, meta.tickets, newRerollCost, nextQuota);
      }
    } else if (hit.type === 'leave') {
      this.game.endShop();
      this._closeForgeShop();
    }
  }

  _syncRelicSlots() {
    const run = this.game.getState().run;
    if (!run) return;
    const slots = [];
    const upgrades = run.purchasedUpgrades || [];
    for (let i = 0; i < 8; i++) {
      if (upgrades[i]) {
        const u = upgrades[i];
        slots.push({ id: u.sprite || 'ball', label: u.name });
      } else {
        slots.push(null);
      }
    }
    this.wheel.setSlots(slots);
  }

  // ── Game flow ──
  _syncWheel() {
    const state = this.game.getState();
    if (state.run) {
      this.wheel.setWheel(state.run.wheel);
      const previewBalls = this._inShop
        ? BALANCE.BALLS_PER_ROUND + state.run.specialBalls.length + (state.run.genericBallsBought || 0)
        : state.run.ballsLeft;
      this.wheel.placeBalls(previewBalls, state.run.specialBalls);
      this.wheel.setCorruption(state.run.corruption);
    }
    this.wheel.setCounters(
      state.run ? state.run.score : 0,
      this.game.getState().meta.tickets,
    );
    this.wheel.setRelics(state.run ? state.run.relics : []);
    this.wheel.setSegmentValues(this.game.getSegmentDisplayValues());
    this.wheel.setGoldPockets(BALANCE.GOLD_POCKETS);
    this.wheel.setMissPockets(BALANCE.MISS_POCKETS);
  }

  _onAction() {
    const phase = this.game.getPhase();
    if (phase === 'IDLE' && !this._spinning) {
      this._doSpin();
    }
  }

  /** Auto-advance through non-interactive phases silently. */
  _autoAdvance() {
    let safety = 10;
    while (safety-- > 0) {
      const phase = this.game.getPhase();
      if (phase === 'IDLE') break;
      if (phase === 'FREE_SPIN_OFFER') {
        this.game.declineFreeSpin();
      } else if (phase === 'RESULTS') {
        this.game.continueFromResults();
      } else if (phase === 'CHOICE') {
        this.game.skipChoice();
      } else if (phase === 'SHOP') {
        if (this._inShop) break; // let forge shop handle it
        this.game.endShop();
      } else if (phase === 'GAME_OVER' || phase === 'VICTORY') {
        // Restart run
        this.game.startRun();
      } else break;
    }
    this._syncWheel();
  }

  _updateGaugeUnlocks() {
    const meta = this.game.getState().meta;
    this.wheel.setGaugeUnlocks([
      true,
      meta.unlocks.includes('unlock_gauge_2'),
      meta.unlocks.includes('unlock_gauge_3'),
      true, // gauge 3 = corruption gauge, always visible
    ]);
  }

  async _doSpin() {
    if (this._spinning) return;
    this._spinning = true;

    this._playSpin();

    this._shakeStart(4, 0.3);
    const startScore = this.game.getState().run.score;
    this.wheel.hubSnapScore(startScore);
    this._goldDisplay = startScore;
    this.wheel.setCounters(startScore, this._lastTicketDisplay);
    const results = await this.wheel.spinAndEject();
    this._stopSpin();

    // Reveal sequence
    for (let i = 0; i < results.length; i++) {
      const result = this.game.resolveBallAt(results[i]);
      if (!result) continue;

      this.wheel.highlight(results[i]);
      this.wheel.hubShowValue(result.result.segment?.symbolId, result.value);
      this.wheel.hubSetScore(this.game.getState().run.score);
      this._goldDisplay = this.game.getState().run.score;
      const run2 = this.game.getState().run;
      this._playReveal(i, results.length);
      const pos = this.wheel.getPocketPosition(results[i], WHEEL_CX, WHEEL_CY);
      this.wheel.startGoldFly('+' + result.value, result.value, pos.x, pos.y - 15, WHEEL_CX, WHEEL_CY);


      // Shake on quota reached + invert flash + bonus mode
      const run3 = this.game.getState().run;
      if (!this._bonusMode && run3.score >= getQuota(run3.round) && run3.score - result.value < getQuota(run3.round)) {
        this._shakeStart(5, 0.5);
        this._flash = 0.3;
        this.wheel.setBonusMode(true);
      }

      await this._delay(450);
    }

    this._spinning = false;
    this.wheel.setBonusMode(false);

    // Wait for all gold fly anims to finish
    while (this.wheel._goldAnims.length > 0) await this._delay(50);

    // Gold quota deduction animation
    const currentRun = this.game.getState().run;
    const quota = getQuota(currentRun.round - 1); // round already advanced after results
    if (quota > 0) {
      await this._delay(300);
      this.wheel.startGoldQuotaAnim(quota);
      this._shakeStart(3, 0.4);
      while (!this.wheel.goldQuotaAnimDone) await this._delay(50);
      await this._delay(200);
    }

    this._postSpinShow = false;

    // Advance game state through RESULTS → CHOICE → SHOP
    this._advanceToShop();

    // Ticket animation if round passed
    const postState = this.game.getState();
    const postRun = postState.run;
    if (postRun?.lastRoundResult?.passed) {
      const ticketsEarned = BALANCE.TICKETS_PER_ROUND;
      this.wheel.setCounters(this._goldDisplay, postState.meta.tickets - ticketsEarned);
      await this._delay(300);
      this.wheel.startTicketAnim(ticketsEarned);
      this._shakeStart(3, 0.4);
      this._playTicketFanfare();
      // Wait for animation to complete
      while (!this.wheel.ticketAnimDone) await this._delay(50);
      this.wheel.setCounters(this._goldDisplay, postState.meta.tickets);
      await this._delay(200);
    }

    const phase = this.game.getPhase();
    if (phase === 'GAME_OVER' || phase === 'FREE_SPIN_OFFER') {

      // Failed or free spin offered — wait for user click
      this._spinning = false;
      return;
    }
    if (phase === 'VICTORY') {

      await this._delay(1000);
      this._autoAdvance();
      return;
    }

    // Flip wheel to show forge shop
    await this._delay(500);
    this._openForgeShop();
    this.wheel.startFlip();
    this._playFlipToShop();
    await this._delay(600);

    // Wait for shop interaction (resolved by _closeForgeShop)
    await new Promise(resolve => { this._shopResolve = resolve; });

    // Flip back
    this.wheel.startFlip();
    this._playFlipBack();
    await this._delay(600);

    // Auto-advance remaining phases (SHOP→IDLE for next round)
    this._autoAdvance();
  }

  _advanceToShop() {
    let safety = 10;
    while (safety-- > 0) {
      const phase = this.game.getPhase();
      if (phase === 'SHOP') break;
      if (phase === 'GAME_OVER' || phase === 'VICTORY' || phase === 'FREE_SPIN_OFFER') break;
      if (phase === 'RESULTS') {
        this.game.continueFromResults();
      } else if (phase === 'CHOICE') {
        this.game.skipChoice();
      } else break;
    }
  }

  _openForgeShop() {
    const state = this.game.getState();
    const run = state.run;
    if (!run) return;
    const rerollCost = BALANCE.SHOP_REROLL_BASE * Math.pow(2, run.rerollCount || 0);
    const nextQuota = getQuota(run.round + 1);
    this.wheel.placeBalls(BALANCE.BALLS_PER_ROUND + run.specialBalls.length + (run.genericBallsBought || 0), run.specialBalls);
    this.wheel.setShop(run.shopOfferings, state.meta.tickets, rerollCost, nextQuota);
    this._inShop = true;
    if (this._music) this._music.setScene('shop');
  }

  _closeForgeShop() {
    this._inShop = false;
    if (this._shopResolve) {
      const resolve = this._shopResolve;
      this._shopResolve = null;
      resolve();
    }
  }

  _pop(text, x, y, opts) {
    this._pops.push({
      text,
      x: x != null ? x : WHEEL_CX + (Math.random() - 0.5) * 60,
      y: y != null ? y : WHEEL_CY - 50 - Math.random() * 20,
      age: 0,
      noCoin: opts?.noCoin || false,
      color: opts?.color || null,
    });
  }

  // ── Render loop ──
  _loop(time) {
    requestAnimationFrame(t => this._loop(t));
    const dt = Math.min((time - this._lastTime) / 1000, 0.05);
    this._lastTime = time;
    this._time += dt;

    this.wheel.update(dt);

    // Shake decay
    if (this._shake.intensity > 0) {
      this._shake.time += dt;
      const t = Math.min(1, this._shake.time / this._shake.decay);
      const amp = this._shake.intensity * (1 - t);
      this._shake.x = Math.round((Math.random() - 0.5) * 2 * amp);
      this._shake.y = Math.round((Math.random() - 0.5) * 2 * amp);
      if (t >= 1) { this._shake.intensity = 0; this._shake.x = 0; this._shake.y = 0; }
    }

    // Update pops
    for (let i = this._pops.length - 1; i >= 0; i--) {
      this._pops[i].age += dt;
      this._pops[i].y -= dt * 25;
      if (this._pops[i].age > 1.5) this._pops.splice(i, 1);
    }

    this._render();
  }

  // ═══ Pre-rendered background ("Forge Aura") ═══
  _initBackground(wheelData) {
    const BW = W + BG_PAD * 2, BH = H + BG_PAD * 2;
    const c = document.createElement('canvas');
    c.width = BW; c.height = BH;
    const bgCtx = c.getContext('2d');
    bgCtx.imageSmoothingEnabled = false;

    const imgData = bgCtx.createImageData(BW, BH);
    const buf = new Uint32Array(imgData.data.buffer);

    const CX = WHEEL_CX + BG_PAD, CY = WHEEL_CY + BG_PAD;
    // Zone radii for layered darkness
    const ORBIT_OUTER = 115;       // matches RING_R in _drawUIRing — transparent inside
    const AURA_TRANS = 8;          // transition from orbit edge to full aura

    // ── Precompute hiero ring segment arcs (matching wheel wedges) ──
    const numSegs = 16;
    const TWO_PI = Math.PI * 2;
    const initAngle = -Math.PI / 2 - Math.PI / numSegs;
    const hieroArcs = new Float64Array(numSegs + 1);
    for (let i = 0; i <= numSegs; i++) {
      hieroArcs[i] = i * TWO_PI / numSegs;
    }
    // Menu segment lookup { segIndex → { id } }
    const menuSegs = {};
    for (const def of HIERO_MENU_DEFS) {
      const idx = numSegs - def.offsetFromEnd;
      if (idx >= 0 && idx < numSegs) menuSegs[idx] = { id: def.id, glyph: def.glyph };
    }

    // Bayer 4×4 ordered dither matrix (values 0..15)
    const BAYER = [
      [ 0, 8, 2,10],
      [12, 4,14, 6],
      [ 3,11, 1, 9],
      [15, 7,13, 5],
    ];

    // Deterministic hash for glint scatter
    const hash = (x, y) => ((x * 374761393 + y * 668265263) >>> 0) & 255;

    for (let y = 0; y < BH; y++) {
      for (let x = 0; x < BW; x++) {
        const dx = x - CX, dy = y - CY;
        const dist2 = dx * dx + dy * dy;
        const idx = y * BW + x;

        // Inside UI ring — fully transparent (inner disc drawn separately with own parallax)
        if (dist2 < ORBIT_OUTER * ORBIT_OUTER) { buf[idx] = 0; continue; }

        const dist = Math.sqrt(dist2);
        const bayer = BAYER[y & 3][x & 3];

        // ── Zone attenuation (transition at orbit edge → full aura) ──
        let zoneAtt;
        if (dist < ORBIT_OUTER + AURA_TRANS) {
          zoneAtt = (dist - ORBIT_OUTER) / AURA_TRANS;
        } else {
          zoneAtt = 1;
        }

        // ── Edge vignette (darken near canvas borders) ──
        const ex = x - BG_PAD, ey = y - BG_PAD;
        const edgeDist = Math.min(ex, ey, W - 1 - ex, H - 1 - ey);
        const vignette = Math.min(1, edgeDist / 20);

        // ── Radial fade from orbit edge ──
        const radialFade = Math.max(0, 1 - Math.max(0, dist - ORBIT_OUTER) / 90);

        // ── 8 radial light rays (warm spokes) ──
        const angle = Math.atan2(dy, dx);

        // Rim-counter cutout (bottom arc — GAUGE_CONFIGS[2])
        // RIM_R=82.5, counter radii 98.5–103.5, with padding for parallax
        if (dist >= 94 && dist <= 108) {
          const ca = ((angle % (Math.PI * 2)) + Math.PI * 2) % (Math.PI * 2);
          if (ca >= Math.PI / 2 - 0.38 && ca <= Math.PI / 2 + 0.38) {
            buf[idx] = 0; continue;
          }
        }
        const ray = Math.pow(Math.max(0, Math.cos(angle * 4)), 6);

        // ── 4 interstitial wedges (between the 4 golden rays, same cos^6 shape) ──
        const ray2 = Math.pow(Math.max(0, -Math.cos(angle * 4)), 6);

        // ── Concentric ring accents (outside orbit zone) ──
        const ringDist = (dist - ORBIT_OUTER) % 32;
        const ring = (dist > ORBIT_OUTER && ringDist < 1.0) ? 0.25 : 0;

        // ── Hieroglyph ring — detect segment for dithered rendering ──
        let hieroSeg = -1;
        if (dist >= HIERO_INNER && dist <= HIERO_OUTER) {
          let ha = angle - initAngle;
          ha = ((ha % TWO_PI) + TWO_PI) % TWO_PI;
          for (let i = 0; i < numSegs; i++) {
            if (ha < hieroArcs[i + 1]) { hieroSeg = i; break; }
          }
          if (hieroSeg < 0) hieroSeg = numSegs - 1;
        }

        // ── Combined brightness ──
        const inHiero = hieroSeg >= 0;
        const hieroAtt = inHiero ? 1 : zoneAtt; // no fade-out inside hiero ring
        const brightness = inHiero
          ? vignette * 0.80
          : hieroAtt * vignette *
            (0.08 + 0.28 * radialFade + 0.35 * ray * radialFade
             + 0.15 * ray2 * radialFade + ring * radialFade);
        const threshold = brightness * 16;

        if (bayer < threshold) {
          if (inHiero) {
            buf[idx] = (hieroSeg % 2 === 0) ? PAL32.darkRed : PAL32.darkGray;
          } else {
            buf[idx] = (radialFade > 0.35 && ray > 0.15)
              ? PAL32.darkGold
              : (radialFade > 0.35 && ray2 > 0.15)
                ? PAL32.midGray
                : PAL32.darkGray;
          }
        } else {
          if (inHiero) {
            buf[idx] = (hieroSeg % 2 === 0) ? PAL32.darkGray : PAL32.black;
          } else {
            buf[idx] = (radialFade > 0.35 && ray2 > 0.15) ? PAL32.darkGray : PAL32.black;
          }
        }
      }
    }

    // ── Glint scatter (sparse bright specks — dust/sparks in metal) ──
    for (let y = 0; y < BH; y++) {
      for (let x = 0; x < BW; x++) {
        const dx = x - CX, dy = y - CY;
        if (dx * dx + dy * dy < ORBIT_OUTER * ORBIT_OUTER) continue;
        if (hash(x, y) < 2) buf[y * BW + x] = PAL32.midGray;   // ~0.8%
      }
    }

    bgCtx.putImageData(imgData, 0, 0);

    // ── Stamp segment labels into ring (menu icons) ──
    bgCtx.imageSmoothingEnabled = false;
    for (let s = 0; s < numSegs; s++) {
      const midAngle = initAngle + (hieroArcs[s] + hieroArcs[s + 1]) / 2;
      const gcx = CX + Math.cos(midAngle) * HIERO_MID;
      const gcy = CY + Math.sin(midAngle) * HIERO_MID;

      bgCtx.save();
      bgCtx.translate(gcx, gcy);

      const menu = menuSegs[s];
      if (menu) {
        // Menu icon: sprite from assets/menu/ (drawn upright, no rotation)
        drawSpriteCentered(bgCtx, menu.glyph, 0, 0, menu.scale || 1);
        if (menu.id === 'retry') {
          drawTextCentered(bgCtx, 'RETRY', 0, 16, PAL.gold, 2);
        }
      }

      bgCtx.restore();
    }

    // Store menu segment data for hit-testing
    this._menuSegments = [];
    for (let s = 0; s < numSegs; s++) {
      const menu = menuSegs[s];
      if (menu) {
        this._menuSegments.push({
          id: menu.id,
          glyph: menu.glyph,
          segIdx: s,
          startAngle: initAngle + hieroArcs[s],
          endAngle: initAngle + hieroArcs[s + 1],
        });
      }
    }
    this._menuHover = null;

    this._bgCanvas = c;
  }

  // ── Hieroglyph ring hit-test (returns menu id or null) ──
  _hieroHitTest(mx, my) {
    const dx = mx - WHEEL_CX, dy = my - WHEEL_CY;
    const dist2 = dx * dx + dy * dy;
    if (dist2 < HIERO_INNER * HIERO_INNER || dist2 > HIERO_OUTER * HIERO_OUTER) return null;
    const a = Math.atan2(dy, dx);
    for (const seg of this._menuSegments) {
      const sa = seg.startAngle, ea = seg.endAngle;
      // Normalize a into [sa, sa+2π) for wrap-around
      let na = a;
      while (na < sa) na += Math.PI * 2;
      while (na >= sa + Math.PI * 2) na -= Math.PI * 2;
      if (na >= sa && na < ea) return seg.id;
    }
    return null;
  }

  _render() {
    const ctx = this._ctx;
    ctx.imageSmoothingEnabled = false;

    // Draw everything in logical 480×270 space, scaled 2×
    ctx.save();
    ctx.scale(PX, PX);
    ctx.translate(this._shake.x, this._shake.y);

    // Clear previous frame (prevents bleed-through in transparent bg regions)
    ctx.fillStyle = '#000';
    ctx.fillRect(0, 0, W, H);

    // ── Parallax offsets ──
    const px = this._mx;   // -1..1
    const py = this._my;
    const pocketOx = px * 1.0;   // pockets: slowest wheel layer
    const pocketOy = py * 0.6;
    const labelOx  = px * 1.4;   // number ring: medium
    const labelOy  = py * 0.9;
    const wheelOx = px * 1.5;    // wheel base (balls, hub circle)
    const wheelOy = py * 1;
    const rimOx   = px * 2.0;    // rim border: fastest wheel layer
    const rimOy   = py * 1.3;
    const periOx = px * 2;       // gauge + slots: 2px max
    const periOy = py * 2;
    const hudOx = px * 4.5;      // HUD: 4.5px max (fastest)
    const hudOy = py * 3;
    const bgOx = px * 3;           // bg aura (aligned with UI ring)
    const bgOy = py * 2.5;
    const uiOx = px * 3;          // UI ring
    const uiOy = py * 2.5;

    // Background: inner disc (rim parallax) + outer aura (UI ring parallax)
    ctx.fillStyle = '#000';
    ctx.beginPath();
    ctx.arc(WHEEL_CX + rimOx, WHEEL_CY + rimOy, 84, 0, Math.PI * 2);
    ctx.fill();
    ctx.drawImage(this._bgCanvas, -BG_PAD + bgOx, -BG_PAD + bgOy);

    // Menu segment hover highlight (drawn over background)
    if (this._menuHover) {
      const seg = this._menuSegments.find(s => s.id === this._menuHover);
      if (seg) {
        ctx.save();
        ctx.globalAlpha = 0.25;
        ctx.fillStyle = PAL.gold;
        ctx.beginPath();
        ctx.arc(WHEEL_CX + bgOx, WHEEL_CY + bgOy, HIERO_OUTER - 1, seg.startAngle, seg.endAngle);
        ctx.arc(WHEEL_CX + bgOx, WHEEL_CY + bgOy, HIERO_INNER + 1, seg.endAngle, seg.startAngle, true);
        ctx.closePath();
        ctx.fill();
        ctx.globalAlpha = 1;
        ctx.restore();
      }
    }

    // Wheel (parallax layer 1) + peripherals (layer 2)
    const _layers = {
      pocket: { x: pocketOx - wheelOx, y: pocketOy - wheelOy },
      label:  { x: labelOx - wheelOx,  y: labelOy - wheelOy },
      rim:    { x: rimOx - wheelOx,    y: rimOy - wheelOy },
    };
    this.wheel.draw(ctx, WHEEL_CX + wheelOx, WHEEL_CY + wheelOy, periOx - wheelOx, periOy - wheelOy, _layers);

    // UI Ring (parallax layer 2.5 — between slots and title)
    this._drawUIRing(ctx, WHEEL_CX + uiOx, WHEEL_CY + uiOy);

    // Title (parallax layer 3 — moves most) with animated "O" flip
    {
      const scale = 5;
      const fullW = measureText('SPINFORGE') * scale;
      const tx = Math.round(W / 2 + hudOx - fullW / 2);
      const ty = 6 + hudOy;
      const charStep = (CHAR_W + 1) * scale;

      drawText(ctx, 'SPINF', tx, ty, PAL.gold, scale);

      // Periodic flip: every 4s, full 360° rotation over 0.6s
      const flipT = this._time % 4.0;
      const flipDur = 0.6;
      let sY = 1;
      if (flipT < flipDur) sY = Math.cos(flipT / flipDur * Math.PI * 2);
      const oX = tx + 5 * charStep;
      const oCX = oX + CHAR_W * scale / 2;
      const oCY = ty + CHAR_H * scale / 2;
      ctx.save();
      ctx.translate(oCX, oCY);
      ctx.scale(1, sY);
      drawText(ctx, 'O', -CHAR_W * scale / 2, -CHAR_H * scale / 2, PAL.gold, scale);
      ctx.restore();

      drawText(ctx, 'RGE', tx + 6 * charStep, ty, PAL.gold, scale);
    }

    // Commit hash (bottom right)
    drawText(ctx, typeof __COMMIT__ !== 'undefined' ? __COMMIT__ : '???', W - 40, H - 8, PAL.midGray, 1);

    // Gold fly animations (above wheel, below UI)
    this.wheel.drawGoldAnims(ctx, WHEEL_CX + wheelOx, WHEEL_CY + wheelOy);

    this._drawPops(ctx);



    // Hub button (own parallax layer — faster than labels, slower than rim)
    const hubBtnOx = px * 1.7;
    const hubBtnOy = py * 1.1;
    if (!this.wheel.flipped) {
      if (this.game.getPhase() === 'FREE_SPIN_OFFER') {
        this._drawFreeSpinOffer(ctx, hubBtnOx, hubBtnOy);
      } else if (this._gameOverData) {
        this._drawGameOver(ctx, hubBtnOx, hubBtnOy);
      } else {
        this._drawHubBtn(ctx, hubBtnOx, hubBtnOy);
      }
    }

    // Gold quota animation overlay
    this.wheel.drawGoldQuotaAnim(ctx, WHEEL_CX + wheelOx, WHEEL_CY + wheelOy);

    // Ticket animation overlay (above hub, below UI)
    this.wheel.drawTicketAnim(ctx, WHEEL_CX + wheelOx, WHEEL_CY + wheelOy);

    ctx.restore(); // end PX scale

    // ── Invert flash (difference blend) ──
    if (this._flash > 0) {
      this._flash -= 1 / 60;
      ctx.save();
      ctx.globalCompositeOperation = 'difference';
      ctx.globalAlpha = Math.min(1, this._flash / 0.15);
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, CW, CH);
      ctx.restore();
    }

    // ── GPU post-process (quantize + scanlines + vignette) ──
    this._postfx.apply(this._canvas);

    // ── UI overlay (popups — NOT affected by postfx shader) ──
    const uiCtx = this._uiCtx;
    uiCtx.clearRect(0, 0, CW, CH);
    uiCtx.save();
    uiCtx.scale(PX, PX);
    this._drawCatalogue(uiCtx);
    this._drawDebugSprites(uiCtx);
    this._drawThemePicker(uiCtx);
    this._drawRelicTooltip(uiCtx);
    this._drawShopTooltip(uiCtx);

    uiCtx.restore();

    // ── Lights overlay (smooth, NOT quantized) ──
    this._drawLights(wheelOx, wheelOy);
  }

  // ── Light map (screen-mode glow, after quantize for smooth gradients) ──
  _drawLights(wox, woy) {
    const ctx = this._lightsCtx;
    ctx.clearRect(0, 0, CW, CH);

    // Hub glow (always active, stepped pulse)
    if (!this._spinning && !this._inShop) {
      const raw = Math.sin(this._time * 3);
      const stepped = Math.floor(raw * 4) / 4;
      const pulse = 0.12 + 0.08 * stepped;
      this._glow(ctx, (WHEEL_CX + wox) * PX, (WHEEL_CY + woy) * PX, 65 * PX, PAL.gold, pulse);
    }

    // Cursor light (follows mouse, warm)
    const clx = (W / 2 + this._mx * W / 2) * PX;
    const cly = (H / 2 + this._my * H / 2) * PX;
    this._glow(ctx, clx, cly, 80 * PX, PAL.gold, 0.06);

    // Wheel lights (balls + highlights)
    for (const l of this.wheel.lights) {
      this._glow(ctx, (l.x + wox) * PX, (l.y + woy) * PX, l.r * PX, l.color, l.a);
    }
  }

  _glow(ctx, x, y, r, color, alpha) {
    ctx.save();
    ctx.globalAlpha = alpha;
    const grad = ctx.createRadialGradient(x, y, 0, x, y, r);
    grad.addColorStop(0, color);
    grad.addColorStop(0.5, color);
    grad.addColorStop(1, '#000');
    ctx.fillStyle = grad;
    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();
  }

  // ── Hub button (round, drawn on top of everything) ──
  _drawHubBtn(ctx, wox, woy) {
    const r = this.wheel.hubRadius || 42;
    const tilt = this.wheel.tilt || 0.65;
    const t = this._time;
    const pressed = this._spinning || this._postSpinShow;
    const hover = this._hubHover && !pressed;
    const run = this.game.getState().run;
    const quota = run ? getQuota(run.round) : 0;
    const score = run ? run.score : 0;

    ctx.save();
    ctx.translate(WHEEL_CX + wox, WHEEL_CY + woy);
    ctx.scale(1, tilt);

    // Raised by default, higher on hover, flush when pressed
    if (!pressed) ctx.translate(0, hover ? -4 : -2);

    // Fill (blinks gold/darkGold at 4Hz when quota reached during spin)
    const quotaReached = pressed && score >= quota;

    if (quotaReached) {
      ctx.fillStyle = Math.sin(t * 8 * Math.PI) > 0 ? PAL.gold : PAL.darkGold;
    } else {
      ctx.fillStyle = PAL.gold;
    }
    ctx.beginPath(); ctx.arc(0, 0, r, 0, Math.PI * 2);
    ctx.fill();

    // Hover brighten (subtle white overlay on gold)
    if (hover) {
      ctx.fillStyle = PAL.white;
      ctx.globalAlpha = 0.15;
      ctx.beginPath(); ctx.arc(0, 0, r, 0, Math.PI * 2);
      ctx.fill();
      ctx.globalAlpha = 1;
    }

    // Glass sweep (idle only — periodic + hover triggered)
    if (!pressed) {
      const SWEEP_INTERVAL = 3.5;
      const SWEEP_DUR = 0.25;
      const periodicT = t % SWEEP_INTERVAL;
      const hoverT = t - this._sweepTrigger;
      const sweepActive = periodicT < SWEEP_DUR || (hoverT >= 0 && hoverT < SWEEP_DUR);
      const sweepProgress = periodicT < SWEEP_DUR ? periodicT / SWEEP_DUR :
                            (hoverT >= 0 && hoverT < SWEEP_DUR) ? hoverT / SWEEP_DUR : -1;
      if (sweepActive && sweepProgress >= 0) {
        const sx = -r + sweepProgress * r * 2;
        ctx.save();
        ctx.beginPath(); ctx.arc(0, 0, r - 2, 0, Math.PI * 2); ctx.clip();
        ctx.fillStyle = PAL.white;
        ctx.globalAlpha = 0.65;
        for (let dy = -r; dy <= r; dy += 1) {
          ctx.fillRect(Math.round(sx + dy * 0.4), dy, 3, 1);
        }
        ctx.globalAlpha = 1;
        ctx.restore();
      }
    }

    // Pressed overlay (darken, only if quota NOT yet reached)
    if (pressed && !quotaReached) {
      ctx.fillStyle = PAL.black;
      ctx.globalAlpha = 0.3;
      ctx.beginPath(); ctx.arc(0, 0, r, 0, Math.PI * 2);
      ctx.fill();
      ctx.globalAlpha = 1;
    }

    if (pressed) {
      if (quotaReached) {
        // Quota reached: score/quota line, BONUS, +surplus with coin
        const surplus = score - quota;
        drawTextCentered(ctx, score + '/' + quota, 0, -Math.floor(CHAR_H * 3), PAL.gold, 1, false);
        drawTextCentered(ctx, 'BONUS', 0, -Math.floor(CHAR_H * 1), PAL.black, 1, false);
        const bStr = '+' + surplus;
        const bW = bStr.length * CHAR_W * 2;
        const bY = Math.floor(CHAR_H * 1.5);
        const bCoinW = SPRITE_SIZE * 2;
        const bOx = Math.round(-(2 + bCoinW) / 2);
        drawTextCentered(ctx, bStr, bOx, bY, PAL.gold, 2);
        drawAnimSpriteCentered(ctx, 'coin', Math.round(bOx + bW / 2 + 2 + SPRITE_SIZE), bY + CHAR_H, 2, t, 8);
      } else {
        // During spin: score with coin (scale 2), /quota below without coin
        const sStr = String(score);
        const sW = sStr.length * CHAR_W * 2;
        const sY = -Math.floor(CHAR_H * 1.5);
        drawTextCentered(ctx, sStr, 0, sY, PAL.gold, 2);
        drawAnimSpriteCentered(ctx, 'coin', Math.round(sW / 2 + 2 + SPRITE_SIZE), sY + CHAR_H, 2, t, 8);
        drawTextCentered(ctx, '/' + quota, 0, Math.floor(CHAR_H * 1.5), PAL.darkGray, 2, false);
      }
    } else {
      // Idle: SPIN label + quota with coin on right
      drawTextCentered(ctx, 'SPIN', 0, -Math.floor(CHAR_H * 1.5), PAL.black, 2, false);
      const qStr = 'QUOTA ' + quota;
      const qW = qStr.length * CHAR_W;
      const qY = Math.floor(CHAR_H * 0.5);
      const coinSz = SPRITE_SIZE;
      const qGap = 1;
      const qOx = Math.round(-(qGap + coinSz) / 2);
      drawTextCentered(ctx, qStr, qOx, qY, PAL.darkGray, 1, false);
      drawAnimSpriteCentered(ctx, 'coin', Math.round(qOx + qW / 2 + qGap + coinSz / 2) + 2, qY + Math.floor(CHAR_H / 2) - 1, 1, t, 4);
    }

    ctx.restore();
  }

  _drawFreeSpinOffer(ctx, wox, woy) {
    const r = this.wheel.hubRadius || 42;
    const tilt = this.wheel.tilt || 0.65;
    const hover = this._hubHover;
    const t = this._time;
    const run = this.game.getState().run;
    const quota = run ? getQuota(run.round) : 0;
    const score = run ? run.score : 0;

    ctx.save();
    ctx.translate(WHEEL_CX + wox, WHEEL_CY + woy);
    ctx.scale(1, tilt);
    ctx.translate(0, hover ? -4 : -2);

    // Pulsing gold/darkGold fill
    ctx.fillStyle = Math.sin(t * 6) > 0 ? PAL.gold : PAL.darkGold;
    ctx.beginPath(); ctx.arc(0, 0, r, 0, Math.PI * 2);
    ctx.fill();

    if (hover) {
      ctx.fillStyle = PAL.white;
      ctx.globalAlpha = 0.15;
      ctx.beginPath(); ctx.arc(0, 0, r, 0, Math.PI * 2);
      ctx.fill();
      ctx.globalAlpha = 1;
    }

    // Score / Quota
    drawTextCentered(ctx, score + '/' + quota, 0, -Math.floor(r * 0.45), PAL.red, 1);

    // DERNIERE CHANCE
    drawTextCentered(ctx, 'DERNIERE', 0, -Math.floor(CHAR_H * 1), PAL.black, 1);
    drawTextCentered(ctx, 'CHANCE', 0, Math.floor(CHAR_H * 0.2), PAL.black, 2);

    // Ball sprite + SPIN GRATUIT
    drawSpriteCentered(ctx, 'ball', 0, Math.floor(r * 0.35), 2);
    drawTextCentered(ctx, 'SPIN GRATUIT', 0, Math.floor(r * 0.58), PAL.white, 1);

    ctx.restore();
  }

  _drawGameOver(ctx, wox, woy) {
    const r = this.wheel.hubRadius || 42;
    const tilt = this.wheel.tilt || 0.65;
    const go = this._gameOverData;
    const hover = this._hubHover;

    ctx.save();
    ctx.translate(WHEEL_CX + wox, WHEEL_CY + woy);
    ctx.scale(1, tilt);
    ctx.translate(0, hover ? -4 : -2);

    // Dark red fill
    ctx.fillStyle = PAL.darkRed;
    ctx.beginPath(); ctx.arc(0, 0, r, 0, Math.PI * 2);
    ctx.fill();

    // Hover brighten
    if (hover) {
      ctx.fillStyle = PAL.white;
      ctx.globalAlpha = 0.1;
      ctx.beginPath(); ctx.arc(0, 0, r, 0, Math.PI * 2);
      ctx.fill();
      ctx.globalAlpha = 1;
    }

    // Skull sprite
    drawSpriteCentered(ctx, 'skull', 0, -Math.floor(r * 0.42), 2);

    // ROUND X
    drawTextCentered(ctx, 'ROUND ' + go.round, 0, -Math.floor(CHAR_H * 0.4), PAL.lightGray, 1);

    // Score / Quota
    drawTextCentered(ctx, go.score + '/' + go.quota, 0, Math.floor(CHAR_H * 0.8), PAL.red, 1);

    // RETRY label + arrow
    drawSpriteCentered(ctx, 'arrow_right', 0, Math.floor(r * 0.35), 3);
    drawTextCentered(ctx, 'RETRY', 0, Math.floor(r * 0.55), PAL.gold, 2);

    ctx.restore();
  }

  // ── UI Ring (gold + tickets + balls along right arc) ──
  _drawUIRing(ctx, cx, cy) {
    const RING_R = 115;

    // Ring outline
    ctx.beginPath();
    ctx.arc(cx, cy, RING_R, 0, Math.PI * 2);
    ctx.strokeStyle = PAL.midGray;
    ctx.lineWidth = 1;
    ctx.stroke();

    // Counters moved to PixelWheel rim (bottom gauge area)
  }

  _drawShopTooltip(ctx) {
    if (!this._inShop) return;
    const offering = this.wheel.shopHoveredOffering;
    if (!offering) return;

    const RARITY_COL = { common: PAL.white, uncommon: PAL.green, rare: PAL.blue, legendary: PAL.gold };
    const TYPE_LABELS = { symbol: 'SYMBOLE', special_ball: 'BILLE SPECIALE', relic: 'RELIQUE' };
    const col = RARITY_COL[offering.rarity] || PAL.white;

    const PAD = 4;
    const LINE_H = 8;
    const PW = 160;
    const descMaxW = PW - PAD * 2;

    // Pre-calc description wrap height
    const desc = (offering.description || '').toUpperCase();
    const words = desc.split(' ');
    let descLines = 0;
    let line = '';
    for (const word of words) {
      const test = line ? line + ' ' + word : word;
      if (measureText(test) > descMaxW && line) {
        descLines++;
        line = word;
      } else {
        line = test;
      }
    }
    if (line) descLines++;
    descLines = Math.max(1, descLines);

    const HEADER_H = 10;
    const TYPE_H = 8;
    const PH = PAD * 3 + HEADER_H + TYPE_H + descLines * LINE_H;

    const PX0 = Math.floor((W - PW) / 2);
    const PY0 = H - PH - 8;

    // Backdrop
    ctx.fillStyle = 'rgba(0,0,0,0.88)';
    ctx.fillRect(PX0 - 1, PY0 - 1, PW + 2, PH + 2);
    ctx.fillStyle = PAL.black;
    ctx.fillRect(PX0, PY0, PW, PH);
    ctx.strokeStyle = col;
    ctx.lineWidth = 1;
    ctx.strokeRect(PX0 + 0.5, PY0 + 0.5, PW - 1, PH - 1);

    // Header: item name
    const title = (offering.name || offering.id || '???').toUpperCase();
    drawTextCentered(ctx, title, PX0 + Math.floor(PW / 2), PY0 + PAD, col);

    // Type label
    const typeLabel = TYPE_LABELS[offering.shopType] || '';
    drawTextCentered(ctx, typeLabel, PX0 + Math.floor(PW / 2), PY0 + PAD + HEADER_H, PAL.midGray);

    // Description (word-wrapped)
    drawTextWrapped(ctx, offering.description || '', PX0 + PAD, PY0 + PAD * 2 + HEADER_H + TYPE_H, descMaxW, PAL.lightGray, 1);
  }

  _drawRelicTooltip(ctx) {
    const rarity = this._relicHoverRarity;
    if (!rarity) return;
    const state = this.game.getState();
    const run = state.run;
    if (!run) return;

    const RARITY_NAMES = { common: 'COMMUNE', uncommon: 'PEU COMMUNE', rare: 'RARE', legendary: 'LEGENDAIRE' };
    const RARITY_COL = { common: PAL.white, uncommon: PAL.green, rare: PAL.blue, legendary: PAL.gold };
    const col = RARITY_COL[rarity] || PAL.white;

    // Gather owned relics of this rarity
    const owned = run.relics.filter(r => r.rarity === rarity);

    const LINE_H = 8; // (H + 2) * scale for wrapped text
    const PAD = 4;
    const HEADER_H = 12;
    const PW = 200;
    const DESC_X_OFF = 90;
    const descMaxW = PW - DESC_X_OFF - PAD;

    // Pre-calculate row heights (name line + wrapped description lines)
    const rowInfos = owned.map(r => {
      const def = RELIC_MAP.get(r.id);
      const desc = def ? def.description : '';
      const descUpper = desc.toUpperCase();
      const words = descUpper.split(' ');
      let descLines = 0;
      let line = '';
      for (const word of words) {
        const test = line ? line + ' ' + word : word;
        if (measureText(test) > descMaxW && line) {
          descLines++;
          line = word;
        } else {
          line = test;
        }
      }
      if (line) descLines++;
      return { name: def ? def.name : r.id, desc, descLines: Math.max(1, descLines), relic: r };
    });

    const ROW_H = 10; // base row for sprite + name
    let totalBodyH = 0;
    if (owned.length === 0) {
      totalBodyH = ROW_H;
    } else {
      for (const info of rowInfos) {
        totalBodyH += Math.max(ROW_H, info.descLines * LINE_H) + 2;
      }
    }
    const PH = HEADER_H + totalBodyH + PAD * 3;

    // Position: below the relic bar (top gauge), centered horizontally
    const PX0 = Math.floor((W - PW) / 2);
    const PY0 = WHEEL_CY - 60;

    // Backdrop
    ctx.fillStyle = 'rgba(0,0,0,0.88)';
    ctx.fillRect(PX0 - 1, PY0 - 1, PW + 2, PH + 2);
    ctx.fillStyle = PAL.black;
    ctx.fillRect(PX0, PY0, PW, PH);
    ctx.strokeStyle = col;
    ctx.lineWidth = 1;
    ctx.strokeRect(PX0 + 0.5, PY0 + 0.5, PW - 1, PH - 1);

    // Header
    drawTextCentered(ctx, RARITY_NAMES[rarity], PX0 + Math.floor(PW / 2), PY0 + PAD, col);

    // Relic list
    let curY = PY0 + PAD + HEADER_H;
    if (owned.length === 0) {
      drawTextCentered(ctx, 'AUCUNE', PX0 + Math.floor(PW / 2), curY, PAL.midGray);
    } else {
      for (const info of rowInfos) {
        // Sprite + name
        drawSpriteCentered(ctx, 'relic_' + rarity, PX0 + PAD + Math.floor(SPRITE_SIZE / 2), curY + Math.floor(ROW_H / 2), 1);
        drawText(ctx, info.name, PX0 + PAD + SPRITE_SIZE + 2, curY, col);
        // Description (word-wrapped)
        drawTextWrapped(ctx, info.desc, PX0 + DESC_X_OFF, curY, descMaxW, PAL.midGray, 1);
        curY += Math.max(ROW_H, info.descLines * LINE_H) + 2;
      }
    }
  }

  // ── Popups ──
  _drawPops(ctx) {
    for (const p of this._pops) {
      const col = p.color || (p.age < 1.0 ? PAL.gold : PAL.darkGold);
      const px = Math.round(p.x);
      const py = Math.round(p.y);
      const alpha = p.age < 1.0 ? 1 : Math.max(0, 1 - (p.age - 1.0) / 0.5);
      ctx.globalAlpha = alpha;
      if (p.noCoin) {
        drawTextCenteredOutlined(ctx, p.text, px, py, col, 1);
      } else {
        const textW = p.text.length * CHAR_W;
        const coinSz = SPRITE_SIZE;
        const totalW = coinSz + 2 + textW;
        drawTextCenteredOutlined(ctx, p.text, Math.round(px - totalW / 2 + textW / 2), py, col, 1);
        drawAnimSpriteCentered(ctx, 'coin', Math.round(px - totalW / 2 + textW + 2 + coinSz / 2), py + Math.floor(CHAR_H / 2), 1, this._time, 6);
      }
      ctx.globalAlpha = 1;
    }
  }

  // ── Audio ──
  _initAudio() {
    if (this._audioCtx) return;
    this._audioCtx = getIntroAudioCtx() || new (window.AudioContext || window.webkitAudioContext)();
    this._chipEngine = getChiptuneEngine(this._audioCtx);
    this._chipEngine.init(this._audioCtx);
    this._chipEngine.masterVolume = 0.5;
    this._chipEngine.bgmVolume = 0.45;
    this._chipEngine.sfxVolume = 0.8;
    this._music = new MusicManager(this._chipEngine);
    const round = this.game.getState().run?.round || 1;

  }

  _tone(freq, dur, type = 'square', vol = 0.06) {
    if (!this._audioCtx) return;
    const o = this._audioCtx.createOscillator(), g = this._audioCtx.createGain();
    o.type = type; o.frequency.value = freq;
    g.gain.setValueAtTime(vol, this._audioCtx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, this._audioCtx.currentTime + dur);
    o.connect(g).connect(this._audioCtx.destination); o.start(); o.stop(this._audioCtx.currentTime + dur);
  }

  _tick() { this._tone(800 + Math.random() * 400, 0.02, 'square', 0.03); }

  _playEject() {
    this._tone(1400 + Math.random() * 200, 0.04, 'sine', 0.05);
    setTimeout(() => this._tone(900 + Math.random() * 200, 0.03, 'square', 0.03), 20);
  }

  _playReveal(idx, total) {
    const notes = [523, 587, 659, 784, 880, 1047];
    const f = notes[Math.min(idx, notes.length - 1)];
    this._tone(f, 0.2, 'square', 0.08);
    setTimeout(() => this._tone(f * 1.5, 0.15, 'sine', 0.04), 50);
  }

  _playStreak() {}

  _playSpin() {
    if (!this._audioCtx) return;
    this._killSpin();
    // Filtered noise (mechanical whirr, not engine drone)
    const bufLen = this._audioCtx.sampleRate * 2;
    const buf = this._audioCtx.createBuffer(1, bufLen, this._audioCtx.sampleRate);
    const data = buf.getChannelData(0);
    for (let i = 0; i < bufLen; i++) data[i] = Math.random() * 2 - 1;
    this._spinNoise = this._audioCtx.createBufferSource();
    this._spinNoise.buffer = buf;
    this._spinNoise.loop = true;
    this._spinFilter = this._audioCtx.createBiquadFilter();
    this._spinFilter.type = 'bandpass';
    this._spinFilter.frequency.value = 300;
    this._spinFilter.Q.value = 2;
    this._spinGain = this._audioCtx.createGain();
    this._spinGain.gain.value = 0.03;
    this._spinNoise.connect(this._spinFilter);
    this._spinFilter.connect(this._spinGain);
    this._spinGain.connect(this._audioCtx.destination);
    this._spinNoise.start();
    this._spinInterval = setInterval(() => {
      const spd = Math.min(1, this.wheel.speed / 18);
      if (this._spinFilter) this._spinFilter.frequency.value = 200 + spd * 800;
      if (this._spinGain) this._spinGain.gain.value = 0.01 + spd * 0.04;
    }, 50);
  }

  _stopSpin() {
    clearInterval(this._spinInterval);
    this._spinInterval = null;
    if (!this._spinGain) return;
    try {
      this._spinGain.gain.setValueAtTime(this._spinGain.gain.value, this._audioCtx.currentTime);
      this._spinGain.gain.exponentialRampToValueAtTime(0.001, this._audioCtx.currentTime + 0.3);
    } catch {}
    setTimeout(() => this._killSpin(), 350);
  }

  _killSpin() {
    try { this._spinNoise?.stop(); } catch {}
    this._spinNoise = null;
    this._spinFilter = null;
    this._spinGain = null;
  }

  _playCoin() {
    this._tone(1200, 0.08, 'sine', 0.08);
    setTimeout(() => this._tone(1600, 0.06, 'sine', 0.06), 60);
  }

  _playSelect() {
    this._tone(660, 0.06, 'square', 0.06);
    setTimeout(() => this._tone(880, 0.08, 'square', 0.06), 50);
  }

  _playHover() {
    this._tone(1100, 0.03, 'sine', 0.03);
  }

  _playBuy() {
    // Cha-ching: metallic ascending triad + shimmer
    this._tone(880, 0.10, 'square', 0.07);
    setTimeout(() => this._tone(1175, 0.10, 'square', 0.07), 60);
    setTimeout(() => this._tone(1760, 0.18, 'sine', 0.09), 120);
    setTimeout(() => this._tone(2640, 0.12, 'sine', 0.04), 180);
  }

  _playFlipToShop() {
    if (!this._audioCtx) return;
    const ctx = this._audioCtx;
    // Ascending whoosh (inverse of _playFlipBack)
    const bufLen = ctx.sampleRate * 0.25;
    const buf = ctx.createBuffer(1, bufLen, ctx.sampleRate);
    const d = buf.getChannelData(0);
    for (let i = 0; i < bufLen; i++) d[i] = Math.random() * 2 - 1;
    const src = ctx.createBufferSource();
    src.buffer = buf;
    const flt = ctx.createBiquadFilter();
    flt.type = 'bandpass'; flt.Q.value = 3;
    flt.frequency.setValueAtTime(200, ctx.currentTime);
    flt.frequency.exponentialRampToValueAtTime(1400, ctx.currentTime + 0.20);
    const g = ctx.createGain();
    g.gain.setValueAtTime(0.06, ctx.currentTime);
    g.gain.linearRampToValueAtTime(0.08, ctx.currentTime + 0.05);
    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.25);
    src.connect(flt).connect(g).connect(ctx.destination);
    src.start(); src.stop(ctx.currentTime + 0.25);
    // Mid-flip metallic clunk
    setTimeout(() => this._tone(250, 0.08, 'square', 0.07), 200);
    setTimeout(() => this._tone(190, 0.06, 'triangle', 0.05), 220);
    // Landing impact
    setTimeout(() => {
      this._tone(130, 0.12, 'square', 0.08);
      this._tone(95, 0.15, 'triangle', 0.06);
    }, 420);
  }

  _playFlipBack() {
    if (!this._audioCtx) return;
    // Descending whoosh (filtered noise burst)
    const ctx = this._audioCtx;
    const bufLen = ctx.sampleRate * 0.25;
    const buf = ctx.createBuffer(1, bufLen, ctx.sampleRate);
    const d = buf.getChannelData(0);
    for (let i = 0; i < bufLen; i++) d[i] = Math.random() * 2 - 1;
    const src = ctx.createBufferSource();
    src.buffer = buf;
    const flt = ctx.createBiquadFilter();
    flt.type = 'bandpass'; flt.Q.value = 3;
    flt.frequency.setValueAtTime(1400, ctx.currentTime);
    flt.frequency.exponentialRampToValueAtTime(200, ctx.currentTime + 0.20);
    const g = ctx.createGain();
    g.gain.setValueAtTime(0.06, ctx.currentTime);
    g.gain.linearRampToValueAtTime(0.08, ctx.currentTime + 0.05);
    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.25);
    src.connect(flt).connect(g).connect(ctx.destination);
    src.start(); src.stop(ctx.currentTime + 0.25);
    // Mid-flip metallic clunk (synced with onFlipMid ~0.22s)
    setTimeout(() => this._tone(220, 0.08, 'square', 0.07), 200);
    setTimeout(() => this._tone(165, 0.06, 'triangle', 0.05), 220);
    // Landing impact (synced with onFlipDone ~0.45s)
    setTimeout(() => {
      this._tone(110, 0.12, 'square', 0.08);
      this._tone(85, 0.15, 'triangle', 0.06);
    }, 420);
  }

  _playTicketFanfare() {
    // Triumphant ascending arpeggio with shimmer
    this._tone(660, 0.12, 'square', 0.06);
    setTimeout(() => this._tone(880, 0.12, 'square', 0.06), 80);
    setTimeout(() => this._tone(1100, 0.15, 'sine', 0.08), 160);
    setTimeout(() => this._tone(1320, 0.20, 'sine', 0.07), 260);
    setTimeout(() => this._tone(1760, 0.30, 'sine', 0.05), 380);
  }

  _delay(ms) { return new Promise(r => setTimeout(r, ms)); }

  _shakeStart(intensity, decay) {
    this._shake.intensity = intensity;
    this._shake.decay = decay;
    this._shake.time = 0;
  }


}

